t.script:
(async function() {
    var profile = await LiffApp.init();
    if (profile) {
        document.getElementById('line_user_id').value = profile.userId;
        var nameField = document.getElementById('liff_name');
        if (!nameField.value) {
            nameField.value = profile.displayName;
        }
    }
})();

                var STATUS_LABELS = ;
                var STATUS_COLORS = ;
                var CASE_TYPE_LABELS = ;

                var currentFilter = 'all';

                async function loadCases(filter) {
                    currentFilter = filter || 'all';
                    var listEl = document.getElementById('cases-list');
                    listEl.innerHTML = '
';

                    try {
                        var result = await LiffApp.fetchJson('/liff/cases/data', {
                            line_user_id: LiffApp.getUserId(),
                            status_filter: currentFilter,
                        });

                        if (result.error) {
                            document.getElementById('cases-list').style.display = 'none';
                            document.getElementById('filter-tabs').style.display = 'none';
                            document.getElementById('auth-error').style.display = 'block';
                            document.getElementById('auth-error-msg').textContent = result.message || 'ไม่มีสิทธิ์เข้าถึง';
                            return;
                        }

                        // Update header
                        var headerEl = document.getElementById('lawyer-header');
                        headerEl.style.display = 'flex';
                        document.getElementById('lawyer-name').textContent = result.lawyer_name;
                        document.getElementById('lawyer-avatar').textContent = (result.lawyer_name || '?')[0];
                        document.getElementById('lawyer-count').textContent = result.total + ' คดี';

                        // Render cases
                        if (!result.cases || result.cases.length === 0) {
                            listEl.innerHTML = '

📂
ไม่มีคดี';
                            return;
                        }

                        var html = '';
                        for (var i = 0; i < result.cases.length; i++) {
                            var c = result.cases[i];
                            var statusLabel = STATUS_LABELS[c.case_status] || c.case_status;
                            var statusColor = STATUS_COLORS[c.case_status] || '#95a5a6';
                            var typeLabel = CASE_TYPE_LABELS[c.case_type] || c.case_type;
                            var courtInfo = '';
                            if (c.next_court_date) {
                                courtInfo = LiffApp.formatDateTime(c.next_court_date);
                            }

                            html += ''
                                + '
'
                                + '' + escHtml(c.name) + ''
                                + '' + escHtml(statusLabel) + ''
                                + ''
                                + '
' + escHtml(c.partner_name) + ' | ' + escHtml(typeLabel) + ''
                                + '
'
                                + (courtInfo ? '⚖ ' + courtInfo + '' : '')
                                + ''
                                + '';
                        }
                        listEl.innerHTML = html;

                    } catch(e) {
                        listEl.innerHTML = '
โหลดข้อมูลไม่ได้: ' + escHtml(e.message) + '';
                    }
                }

                function escHtml(s) {
                    if (!s) return '';
                    var d = document.createElement('div');
                    d.textContent = s;
                    return d.innerHTML;
                }

                // Tab click handler
                document.getElementById('filter-tabs').addEventListener('click', function(e) {
                    var btn = e.target.closest('.liff-tab');
                    if (!btn) return;
                    document.querySelectorAll('.liff-tab').forEach(function(t) { t.classList.remove('active'); });
                    btn.classList.add('active');
                    loadCases(btn.getAttribute('data-filter'));
                });

                // Init
                (async function() {
                    await LiffApp.init();
                    if (!LiffApp.getUserId()) {
                        document.getElementById('cases-list').style.display = 'none';
                        document.getElementById('filter-tabs').style.display = 'none';
                        document.getElementById('auth-error').style.display = 'block';
                        document.getElementById('auth-error-msg').textContent = 'กรุณาเปิดผ่าน LINE';
                        return;
                    }
                    loadCases('all');
                })();

body.script:
// Fallback: if main script didn't run after 3s, retry inline
setTimeout(function() {
    var loading = document.getElementById('init-loading');
    if (loading && loading.style.display !== 'none') {
        console.log('[doc-create] fallback: main script may not have loaded, retrying inline');
        fetch('/liff/document/create/data', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: { line_user_id: '' } })
        })
        .then(function(r) { return r.json(); })
        .then(function(j) {
            loading.style.display = 'none';
            if (j.error) {
                document.getElementById('auth-error').style.display = 'block';
                document.getElementById('auth-error-msg').textContent = j.error.message || 'Error';
                return;
            }
            var res = j.result;
            if (typeof allTemplates !== 'undefined') {
                allTemplates = res.templates || [];
                allCases = res.cases || [];
            }
            document.getElementById('doc-main').style.display = 'block';
        })
        .catch(function(e) {
            loading.style.display = 'none';
            document.getElementById('auth-error').style.display = 'block';
            document.getElementById('auth-error-msg').textContent = 'โหลดไม่ได้: ' + e.message;
        });
    }
}, 3000);

var STATE_COLORS = {
    generating:'#f39c12', draft:'#3498db', sent_to_client:'#9b59b6',
    revision:'#e67e22', final:'#2ecc71', signed:'#27ae60',
    cancelled:'#95a5a6', expired:'#bdc3c7'
};
var allDocs = [];
var currentFilter = 'all';

function loadDocs() {
    var uid = '';
    try {
        if (window.liff) uid = liff.getDecodedIDToken().sub || '';
    } catch(e) {}
    fetch('/liff/documents/data', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({jsonrpc:'2.0', method:'call', params:{line_user_id: uid}})
    })
    .then(function(r){return r.json();})
    .then(function(j){
        allDocs = (j.result || {}).documents || [];
        renderDocs();
    });
}

function renderDocs() {
    var list = document.getElementById('doc-list');
    var empty = document.getElementById('doc-empty');
    var filtered = currentFilter === 'all' ? allDocs : allDocs.filter(function(d){return d.state === currentFilter;});
    if (!filtered.length) {
        list.innerHTML = '';
        empty.style.display = 'block';
        return;
    }
    empty.style.display = 'none';
    list.innerHTML = filtered.map(function(d) {
        var bg = STATE_COLORS[d.state] || '#999';
        return ''
            + '
' + esc(d.name)
            + '' + esc(d.state_label) + ''
            + ''
            + '
'
            + (d.template_name ? esc(d.template_name) + ' · ' : '')
            + esc(d.create_date)
            + (d.revision_count > 0 ? ' · แก้ไข ' + d.revision_count + ' ครั้ง' : '')
            + '';
    }).join('');
}

function esc(s) {
    if (!s) return '';
    var d = document.createElement('div');
    d.textContent = s;
    return d.innerHTML;
}

document.getElementById('filter-bar').addEventListener('click', function(e) {
    var btn = e.target.closest('.filter-btn');
    if (!btn) return;
    document.querySelectorAll('.filter-btn').forEach(function(b){b.classList.remove('active');});
    btn.classList.add('active');
    currentFilter = btn.dataset.filter;
    renderDocs();
});

loadDocs();
